// UserPreferences stores user-specific settings.
type UserPreferences map[string]string

// Session represents a user's session data.
type Session struct {
	ID           string
	UserID       string
	Preferences  UserPreferences
	Permissions  []string
	CreatedAt    time.Time
	LastAccessed time.Time
}

// SessionStore manages sessions in memory and persists them to disk using gob encoding.
type SessionStore struct {
	sessions   map[string]*Session
	mu         sync.RWMutex
	sessionDir string // Directory to store session files
}

// NewSessionStore creates a new SessionStore, initializes it, and attempts to load existing sessions from disk.
// It also starts a background goroutine for periodic saving.
func NewSessionStore(sessionDir string) (*SessionStore, error) {
	if err := os.MkdirAll(sessionDir, 0755); err != nil {
		return nil, fmt.Errorf("failed to create session directory %s: %w", sessionDir, err)
	}

	store := &SessionStore{
		sessions:   make(map[string]*Session),
		sessionDir: sessionDir,
	}

	// Register types for gob encoding. This is crucial for custom types.
	gob.Register(Session{})
	gob.Register(UserPreferences{}) // Registering map types can prevent issues

	if err := store.LoadFromDisk(); err != nil {
		// Log a warning if loading fails but continue with an empty store.
		// This allows the server to start even if session files are corrupted or missing.
		fmt.Printf("Warning: Failed to load sessions from disk: %v\n", err)
	}

	// Start a background goroutine to periodically save sessions to disk
	go store.autoSave()

	return store, nil
}

// autoSave periodically saves all sessions to disk.
func (s *SessionStore) autoSave() {
	ticker := time.NewTicker(5 * time.Minute) // Save every 5 minutes
	defer ticker.Stop()

	for range ticker.C {
		if err := s.SaveToDisk(); err != nil {
			fmt.Printf("Error during auto-save: %v\n", err)
		} else {
			fmt.Println("Sessions auto-saved to disk.")
		}
	}
}

// generateSessionID creates a new unique session ID using UUID.
func (s *SessionStore) generateSessionID() string {
	return uuid.New().String()
}

// CreateSession creates a new session, adds it to the store, and returns it.
func (s *SessionStore) CreateSession(userID string, preferences UserPreferences, permissions []string) *Session {
	s.mu.Lock()
	defer s.mu.Unlock()

	sessionID := s.generateSessionID()
	now := time.Now()
	session := &Session{
		ID:           sessionID,
		UserID:       userID,
		Preferences:  preferences,
		Permissions:  permissions,
		CreatedAt:    now,
		LastAccessed: now,
	}
	s.sessions[sessionID] = session
	return session
}

// GetSession retrieves a session by its ID. It also updates the LastAccessed timestamp.
func (s *SessionStore) GetSession(sessionID string) *Session {
	s.mu.RLock()
	session, ok := s.sessions[sessionID]
	s.mu.RUnlock()

	if ok {
		s.mu.Lock() // Promote to write lock to update LastAccessed
		session.LastAccessed = time.Now()
		s.mu.Unlock()
	}
	return session
}

// UpdateSession updates an existing session with new data.
func (s *SessionStore) UpdateSession(session *Session) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.sessions[session.ID]; !ok {
		return fmt.Errorf("session with ID %s not found", session.ID)
	}
	session.LastAccessed = time.Now()
	s.sessions[session.ID] = session // Overwrite with updated session
	return nil
}

// DeleteSession removes a session from the store and its corresponding file from disk.
func (s *SessionStore) DeleteSession(sessionID string) {
	s.mu.Lock()
	defer s.mu.Unlock()

	delete(s.sessions, sessionID)
	sessionFilePath := filepath.Join(s.sessionDir, sessionID+".gob")
	if err := os.Remove(sessionFilePath); err != nil && !os.IsNotExist(err) {
		fmt.Printf("Error deleting session file %s: %v\n", sessionFilePath, err)
	}
}

// SaveToDisk saves all current sessions from memory to individual gob files in the session directory.
func (s *SessionStore) SaveToDisk() error {
	s.mu.RLock()
	defer s.mu.RUnlock()

	// Iterate over a copy of the map to avoid holding the lock during file I/O
	// and to prevent concurrent modification if the map were modified during iteration (though RLock prevents writes).
	// A simpler approach for small numbers of sessions or if performance isn't critical
	// is to just iterate directly. For this example, direct iteration with RLock is fine.
	for _, session := range s.sessions {
		filePath := filepath.Join(s.sessionDir, session.ID+".gob")
		file, err := os.Create(filePath)
		if err != nil {
			return fmt.Errorf("failed to create session file %s: %w", filePath, err)
		}
		encoder := gob.NewEncoder(file)
		if err := encoder.Encode(session); err != nil {
			file.Close() // Ensure file is closed on error
			return fmt.Errorf("failed to encode session %s to file %s: %w", session.ID, filePath, err)
		}
		file.Close() // Ensure file is closed
	}
	return nil
}

// LoadFromDisk loads sessions from individual gob files stored in the session directory into memory.
func (s *SessionStore) LoadFromDisk() error {
	files, err := ioutil.ReadDir(s.sessionDir)
	if err != nil {
		return fmt.Errorf("failed to read session directory %s: %w", s.sessionDir, err)
	}

	s.mu.Lock() // Acquire write lock as we are modifying the sessions map
	defer s.mu.Unlock()

	for _, fileInfo := range files {
		if fileInfo.IsDir() {
			continue
		}
		if filepath.Ext(fileInfo.Name()) != ".gob" {
			continue
		}

		filePath := filepath.Join(s.sessionDir, fileInfo.Name())
		file, err := os.Open(filePath)
		if err != nil {
			fmt.Printf("Warning: failed to open session file %s: %v\n", filePath, err)
			continue
		}

		var session Session
		decoder := gob.NewDecoder(file)
		if err := decoder.Decode(&session); err != nil {
			fmt.Printf("Warning: failed to decode session from file %s: %v\n", filePath, err)
			file.Close()
			// Consider moving corrupted files to a quarantine directory or deleting them
			continue
		}
		file.Close()

		s.sessions[session.ID] = &session
	}
	return nil
}

