	// Set a session cookie to pass the session ID back to the client.
	// In a production environment, ensure HttpOnly, Secure (for HTTPS), and SameSite attributes are properly configured.
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    session.ID,
		Path:     "/",
		Expires:  time.Now().Add(24 * time.Hour), // Example expiry: 24 hours
		HttpOnly: true,                           // Prevents client-side script access
		Secure:   false,                          // Set to true for HTTPS
		SameSite: http.SameSiteLaxMode,           // Mitigates CSRF
	})

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"message": "Session created", "session_id": session.ID})
